#include <stdio.h>
#include <math.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        double PA;
        scanf("%lf", &PA);
        double coeff_a = (1.0 - PA) * (2.0 * PA - 1.0);
        double coeff_b = PA * (1.0 - 2.0 * PA);
        double maxCoeff = coeff_a;
        if (coeff_b > maxCoeff) maxCoeff = coeff_b;
        if (maxCoeff < 0.0) maxCoeff = 0.0;
        double expected = 10000.0 + maxCoeff * 10000.0;
        long long ans = (long long)floor(expected + 1e-9);
        printf("%lld\n", ans);
    }
    return 0;
}

