import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            double PA = Double.parseDouble(br.readLine().trim());
            double coeffA = (1.0 - PA) * (2.0 * PA - 1.0);
            double coeffB = PA * (1.0 - 2.0 * PA);
            double maxCoeff = Math.max(0.0, Math.max(coeffA, coeffB));
            double expected = 10000.0 + maxCoeff * 10000.0;
            long ans = (long)Math.floor(expected + 1e-9);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

